import pytest
import torch
import numpy as np
import sys, os
sys.path.insert(0, os.path.join(os.path.dirname(__file__), '..'))

def normalize(x, mean, std):
    return (x - mean) / (std + 1e-9)

def rolling_zscore(x, window):
    result = np.zeros_like(x, dtype=float)
    for i in range(len(x)):
        if i < window:
            sub = x[:i+1]
        else:
            sub = x[i-window+1:i+1]
        mu, sigma = sub.mean(), sub.std()
        result[i] = (x[i] - mu) / (sigma + 1e-9)
    return result

def compute_returns(prices, log=False):
    if log:
        return np.diff(np.log(prices + 1e-9))
    return np.diff(prices) / (prices[:-1] + 1e-9)

def compute_rsi(prices, period=14):
    deltas = np.diff(prices)
    gains = np.where(deltas > 0, deltas, 0.0)
    losses = np.where(deltas < 0, -deltas, 0.0)
    rsi = np.zeros(len(prices))
    for i in range(period, len(prices)):
        avg_gain = gains[i-period:i].mean()
        avg_loss = losses[i-period:i].mean()
        rs = avg_gain / (avg_loss + 1e-9)
        rsi[i] = 100 - 100 / (1 + rs)
    return rsi

