def test_normalize_zero_mean(N, mu, sigma, seed):
    rng = np.random.default_rng(seed)
    x = rng.normal(mu, sigma, N)
    normed = normalize(x, x.mean(), x.std())
    assert abs(normed.mean()) < 1e-5

