def test_returns_length(N, log_ret, seed, start_price):
    rng = np.random.default_rng(seed)
    rets = rng.normal(0.001, 0.01, N)
    prices = start_price * np.cumprod(1 + rets)
    computed = compute_returns(prices, log=log_ret)
    assert len(computed) == N - 1

