def test_rsi_bounds(N, period, seed):
    rng = np.random.default_rng(seed)
    prices = 100 * np.cumprod(1 + rng.normal(0.001, 0.01, N))
    rsi = compute_rsi(prices, period)
    valid = rsi[period:]
    assert np.all(valid >= 0)
    assert np.all(valid <= 100)
